import React, { useState, useEffect, useRef } from 'react';
import { X, Send } from 'lucide-react';
import { mockChatMessages, mockUsers, addChatMessage } from '../services/mockData';
import { GoogleGenAI } from "@google/genai";

interface ChatViewProps {
  userId: string;
  companionId: string;
  onClose: () => void;
}

const ChatView: React.FC<ChatViewProps> = ({ userId, companionId, onClose }) => {
  const sortedIds = [userId, companionId].sort();
  const chatId = `${sortedIds[0]}_${sortedIds[1]}`;

  const [messages, setMessages] = useState<any[]>(mockChatMessages[chatId] || []);
  const [newMessage, setNewMessage] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const companion = mockUsers.find(u => u.id === companionId);
  const companionEmail = companion ? companion.email : '...';
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Initialize messages for the chat
    setMessages(mockChatMessages[chatId] || []);
  }, [chatId]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  const sendMessage = async () => {
    if (!newMessage.trim()) return;

    const messageText = newMessage;
    setNewMessage(''); // Clear immediately for better UX

    const userMsg = {
      id: `msg_${Date.now()}`,
      senderId: userId,
      text: messageText,
      timestamp: { toDate: () => new Date() },
    };

    // Optimistic update
    addChatMessage(chatId, userMsg);
    setMessages(prev => [...prev, userMsg]);

    // AI Logic: If chatting with the Trainer (trainer01), trigger AI response
    if (companionId === 'trainer01' && userId !== 'trainer01') {
        setIsTyping(true);
        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            // Construct history correctly for the API
            const history = messages.map(m => ({
                role: m.senderId === userId ? 'user' : 'model',
                parts: [{ text: m.text }]
            }));

            const chat = ai.chats.create({
                model: 'gemini-2.5-flash',
                config: {
                    systemInstruction: "Eres Tommy, el entrenador virtual de la app de fitness TommyBox. Tu objetivo es motivar, educar y guiar a los atletas. Eres experto en entrenamiento funcional, nutrición deportiva y prevención de lesiones. Tu tono es enérgico, positivo y profesional. Responde de forma concisa (máximo 3 frases salvo que sea una explicación técnica). Si te preguntan por horarios, precios o citas, sugiere revisar la sección de 'Planes' o 'Agenda' en la app.",
                },
                history: history
            });

            const result = await chat.sendMessage({ message: messageText });
            const responseText = result.text;

            const aiMsg = {
                id: `msg_${Date.now() + 1}`,
                senderId: companionId,
                text: responseText,
                timestamp: { toDate: () => new Date() },
            };

            addChatMessage(chatId, aiMsg);
            setMessages(prev => [...prev, aiMsg]);
        } catch (error) {
            console.error("Error AI:", error);
        } finally {
            setIsTyping(false);
        }
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-end justify-end p-4 md:p-8 pointer-events-none">
      <div className="relative w-full max-w-sm md:max-w-md h-full md:h-2/3 bg-white rounded-2xl shadow-2xl flex flex-col overflow-hidden pointer-events-auto">
        <div className="flex items-center justify-between p-4 bg-gray-100 border-b border-gray-200">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 rounded-full bg-blue-600 flex items-center justify-center text-white font-bold text-sm">
                {(companionEmail || 'A').charAt(0).toUpperCase()}
             </div>
             <div>
                <h2 className="text-base font-bold text-gray-900">{companion?.displayName || companionEmail.split('@')[0]}</h2>
                <p className="text-xs text-green-600 flex items-center gap-1">
                    <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span> En línea
                </p>
             </div>
          </div>
          <button onClick={onClose} className="text-gray-500 hover:text-gray-700 bg-white p-2 rounded-full shadow-sm"><X size={20} /></button>
        </div>

        <div className="flex-1 p-4 space-y-4 overflow-y-auto bg-gray-50">
          {messages.map(msg => (
            <div key={msg.id} className={`flex ${msg.senderId === userId ? 'justify-end' : 'justify-start'}`}>
              <div className={`p-3 rounded-2xl max-w-[85%] text-sm shadow-sm ${msg.senderId === userId ? 'bg-blue-600 text-white rounded-br-none' : 'bg-white text-gray-800 border border-gray-200 rounded-bl-none'}`}>
                <p className="leading-relaxed">{msg.text}</p>
                <span className={`block text-[10px] text-right mt-1 ${msg.senderId === userId ? 'text-blue-100' : 'text-gray-400'}`}>
                  {msg.timestamp?.toDate ? msg.timestamp.toDate().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : 'Justo ahora'}
                </span>
              </div>
            </div>
          ))}

          {isTyping && (
             <div className="flex justify-start animate-fade-in">
                <div className="bg-white border border-gray-200 p-3 rounded-2xl rounded-bl-none shadow-sm flex items-center gap-1">
                    <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></span>
                    <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-75"></span>
                    <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-150"></span>
                </div>
             </div>
          )}
          <div ref={chatEndRef} />
        </div>

        <div className="p-3 bg-white border-t border-gray-200">
          <div className="flex items-center gap-2 bg-gray-100 rounded-full px-4 py-2 border border-gray-200 focus-within:ring-2 focus-within:ring-blue-500/20 focus-within:border-blue-500 transition-all">
            <input
              type="text"
              placeholder="Escribe tu mensaje..."
              value={newMessage}
              onChange={(e) => setNewMessage(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && sendMessage()}
              className="flex-1 bg-transparent border-none focus:outline-none text-sm text-gray-800 placeholder-gray-400"
              autoFocus
            />
            <button 
                onClick={sendMessage} 
                className={`p-2 rounded-full transition-all ${newMessage.trim() ? 'bg-blue-600 text-white shadow-md hover:scale-105' : 'bg-gray-300 text-gray-500 cursor-not-allowed'}`}
                disabled={!newMessage.trim() || isTyping}
            >
              <Send size={18} fill="currentColor" />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ChatView;

