        <input type="email" value={formData.email} onChange={(e) => setFormData({ ...formData, email: e.target.value })} className={`mt-1 block w-full px-3 py-2 border rounded-md ${errors.email ? 'border-red-500' : 'border-gray-300'} focus:ring-blue-500 focus:border-blue-500`} required />
        {errors.email && <p className="mt-1 text-sm text-red-600">{errors.email}</p>}
      </div>
      <div>
        <label className="block text-sm font-medium text-gray-700">Contraseña *</label>
        <div className="relative mt-1">
          <input type={showPassword ? 'text' : 'password'} value={formData.password} onChange={(e) => setFormData({ ...formData, password: e.target.value })} className={`block w-full px-3 py-2 border rounded-md ${errors.password ? 'border-red-500' : 'border-gray-300'} focus:ring-blue-500 focus:border-blue-500`} required />
          <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute inset-y-0 right-0 pr-3 flex items-center text-gray-500 hover:text-gray-700">
            {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
          </button>
        </div>
        {errors.password && <p className="mt-1 text-sm text-red-600">{errors.password}</p>}
      </div>
      <div>
        <label className="block text-sm font-medium text-gray-700">Confirmar Contraseña *</label>
        <div className="relative mt-1">
          <input type={showConfirmPassword ? 'text' : 'password'} value={formData.confirmPassword} onChange={(e) => setFormData({ ...formData, confirmPassword: e.target.value })} className={`block w-full px-3 py-2 border rounded-md ${errors.confirmPassword ? 'border-red-500' : 'border-gray-300'} focus:ring-blue-500 focus:border-blue-500`} required />
          <button type="button" onClick={() => setShowConfirmPassword(!showConfirmPassword)} className="absolute inset-y-0 right-0 pr-3 flex items-center text-gray-500 hover:text-gray-700">
            {showConfirmPassword ? <EyeOff size={20} /> : <Eye size={20} />}
          </button>
        </div>
        {errors.confirmPassword && <p className="mt-1 text-sm text-red-600">{errors.confirmPassword}</p>}
      </div>
      <button type="submit" disabled={isLoading} className="w-full py-3 px-4 bg-green-600 text-white font-medium rounded-md hover:bg-green-700 transition-colors disabled:opacity-50 shadow-md">
        {isLoading ? 'Creando...' : 'Crear Cuenta'}
      </button>
    </form>
  );
};

const LoginView: React.FC<LoginViewProps> = ({ setCurrentView, isLoggedIn, handleLogin, handleRegister, completeRegistration, pendingCompletionUser, setPendingCompletionUser }) => {
  const [mode, setMode] = useState<'login' | 'register'>('login');
  const [showRegistrationModal, setShowRegistrationModal] = useState(false);
  const [userToComplete, setUserToComplete] = useState<(UserProfile & { id: string }) | null>(null);

  useEffect(() => {
    if (isLoggedIn) {
      setCurrentView('dashboard');
    }
  }, [isLoggedIn, setCurrentView]);

  useEffect(() => {
    if (pendingCompletionUser) {
        setUserToComplete(pendingCompletionUser);
        setShowRegistrationModal(true);
    }
  }, [pendingCompletionUser]);

  const onRegisterSuccess = (newUser: UserProfile & { id: string }) => {
    setUserToComplete(newUser);
    setShowRegistrationModal(true);
  };

  const handleModalClose = () => {
    setShowRegistrationModal(false);
    setUserToComplete(null);
    setPendingCompletionUser(null);
  };

  return (
     <section className="container mx-auto px-4 py-16">
      <div className="max-w-md mx-auto rounded-3xl bg-white p-8 shadow-2xl">
        <div className="flex justify-center mb-6">
            <img 
              src="https://i.postimg.cc/rpM8kSt5/20251103_141407_0000.png" 
              alt="TommyBox Logo" 
              className="h-16 object-contain" 
            />
        </div>

        <div className="flex border-b border-gray-200 mb-6">
          <button onClick={() => setMode('login')} className={`flex-1 py-4 text-center font-medium transition-colors ${mode === 'login' ? 'text-blue-600 border-b-2 border-blue-600' : 'text-gray-500'}`}>Iniciar Sesión</button>
          <button onClick={() => setMode('register')} className={`flex-1 py-4 text-center font-medium transition-colors ${mode === 'register' ? 'text-blue-600 border-b-2 border-blue-600' : 'text-gray-500'}`}>Registrarse</button>
        </div>

        {mode === 'login' ? (
          <LoginForm handleLogin={handleLogin} />
        ) : (
          <RegisterForm onRegisterSuccess={onRegisterSuccess} handleRegister={handleRegister} />
        )}
      </div>

      {showRegistrationModal && userToComplete && (
        <RegistrationModal 
          userToComplete={userToComplete}
          onClose={handleModalClose}
          onComplete={completeRegistration}
        />
      )}
    </section>
  );
};

export default LoginView;

