// Robust Scanner Component
const DirectCameraScanner: React.FC<{ onSuccess: (decodedText: string) => void; onCancel: () => void; }> = ({ onSuccess, onCancel }) => {
  const scannerId = useRef(`scanner-${Math.random().toString(36).substr(2, 9)}`).current;
  const scannerRef = useRef<Html5Qrcode | null>(null);

  useEffect(() => {
    let mounted = true;

    const startScanner = async () => {
      const element = document.getElementById(scannerId);
      if (!element) return;
      if (scannerRef.current) return;

      try {
        const html5QrCode = new Html5Qrcode(scannerId);
        scannerRef.current = html5QrCode;

        await html5QrCode.start(
          { facingMode: "environment" },
          {
            fps: 10,
            qrbox: { width: 250, height: 250 },
            aspectRatio: window.innerWidth / window.innerHeight
          },
          (decodedText) => {
             if (mounted) onSuccess(decodedText);
          },
          () => {}
        );
      } catch (err) {
        console.error("Error starting scanner", err);
        if (mounted) onCancel();
      }
    };

    const timer = setTimeout(startScanner, 300);

    return () => {
      mounted = false;
      clearTimeout(timer);
      if (scannerRef.current) {
        scannerRef.current.stop().then(() => {
             if (scannerRef.current) scannerRef.current.clear();
        }).catch(err => console.warn("Failed to stop scanner", err));
      }
    };
  }, [onSuccess, onCancel, scannerId]);

  return (
    <div className="fixed inset-0 z-[100] bg-black">
        {/* 1. Camera Feed Container - Absolute Background */}
        <div id={scannerId} className="absolute inset-0 w-full h-full bg-black"></div>

        {/* 2. Semi-transparent Overlay to dim surrounding area */}
        <div className="absolute inset-0 bg-black/30 pointer-events-none z-10"></div>

        {/* 3. The Scanning Window - Clear and Unobstructed */}
        <div className="absolute inset-0 pointer-events-none flex flex-col items-center justify-center z-20">
             <div className="relative w-64 h-64">
                {/* Visual Frame Corners */}
                <div className="absolute top-0 left-0 w-12 h-12 border-t-4 border-l-4 border-white/80 rounded-tl-3xl"></div>
                <div className="absolute top-0 right-0 w-12 h-12 border-t-4 border-r-4 border-white/80 rounded-tr-3xl"></div>
                <div className="absolute bottom-0 left-0 w-12 h-12 border-b-4 border-l-4 border-white/80 rounded-bl-3xl"></div>
                <div className="absolute bottom-0 right-0 w-12 h-12 border-b-4 border-r-4 border-white/80 rounded-br-3xl"></div>

                {/* Scanning Laser Animation */}
                <div className="absolute top-0 left-0 w-full h-1 bg-blue-500 shadow-[0_0_15px_rgba(59,130,246,1)] animate-[scan_2s_infinite]"></div>

                 {/* Clear center */}
                <div className="w-full h-full border border-white/10 bg-transparent box-border rounded-xl"></div>
             </div>

             <p className="text-white mt-8 font-medium bg-black/60 px-6 py-2 rounded-full backdrop-blur-md text-sm border border-white/10">
                Apunta al código QR del gimnasio
             </p>
        </div>

        {/* 4. Close Button */}
        <button 
            onClick={onCancel} 
            className="absolute top-6 right-6 p-4 bg-white/10 backdrop-blur-md border border-white/20 rounded-full text-white hover:bg-white/20 transition-all z-50 pointer-events-auto"
        >
            <X size={24} />
        </button>

        {/* Force video element to fill container */}
        <style>{`
          #${scannerId} video {
              object-fit: cover !important;
              width: 100% !important;
              height: 100% !important;
          }
          @keyframes scan {
            0% { top: 0; opacity: 0; }
            50% { opacity: 1; }
            100% { top: 100%; opacity: 0; }
          }
        `}</style>
    </div>
  );
};

const DashboardView: React.FC<DashboardViewProps> = ({ trainerId, user, setChatCompanionId, setShowChat, setCurrentView, setRewardQueue }) => {
  const [metrics, setMetrics] = useState<Metric[]>([]);
  const [evaluations, setEvaluations] = useState<Observation[]>([]);
  const [userProfile, setUserProfile] = useState<(UserProfile & {id: string}) | null>(null);
  const [sessionFeeling, setSessionFeeling] = useState('');
  const [message, setMessage] = useState('');
  const [canPostSensation, setCanPostSensation] = useState(true);
  const [showScanner, setShowScanner] = useState(false);
  const [showQrCard, setShowQrCard] = useState(false);
  const [sessionCount, setSessionCount] = useState(0);

  useEffect(() => {
    if (!user?.uid) return;

    const profileData = mockUsers.find(u => u.id === user.uid) as (UserProfile & {id: string}) | undefined;
    if (profileData) setUserProfile(profileData);

    if (!mockDb[user.uid]) {
        mockDb[user.uid] = { metrics: [], observations: [], feelings: [], sessions: [] };
    }

    const clientData = mockDb[user.uid];
    const safeMetrics = clientData.metrics || [];
    const safeObservations = clientData.observations || [];
    const safeSessions = clientData.sessions || [];

    setMetrics([...safeMetrics].sort((a,b) => new Date(a.date).getTime() - new Date(b.date).getTime()));
    setEvaluations([...safeObservations].sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
    setSessionCount(safeSessions.length);
    setCanPostSensation(canPerformAction(user.uid, 'POST_WORKOUT_SENSATION'));

  }, [user?.uid]);

  const handleSaveFeeling = () => {
    if (!sessionFeeling.trim() || !user?.uid) return;
    if (!canPerformAction(user.uid, 'POST_WORKOUT_SENSATION')) {
        setMessage('Ya registraste tu sensación hoy.');
        setTimeout(() => setMessage(''), 3000);
        return;
    }

    const isDetailed = sessionFeeling.length > 50;
    const newFeeling: Feeling = {
      id: `feel_${Date.now()}`,
      feeling: sessionFeeling,
      date: new Date().toISOString().split('T')[0],
      timestamp: { toDate: () => new Date(), toMillis: () => Date.now() } as any,
    };

    const rewards = addFeeling(user.uid, newFeeling, isDetailed);
    if(rewards) setRewardQueue(q => [...q, rewards]);
    incrementActionCount(user.uid, 'POST_WORKOUT_SENSATION');

    setMessage('¡Gracias por tu feedback!');
    setSessionFeeling('');
    setCanPostSensation(false);
    setTimeout(() => setMessage(''), 3000);
  };

  const handleScanSuccess = useCallback((decodedText: string) => {
    setShowScanner(false);
    // Simulate API verification
    if (decodedText === "TOMMYBOX_CHECKIN_2025") {
      if(user?.uid) {
        if(canPerformAction(user.uid, 'CHECK_IN')) {
          const rewards = registerAttendance(user.uid);
          if (rewards) setRewardQueue(q => [...q, rewards]);
          incrementActionCount(user.uid, 'CHECK_IN');
          setMessage('¡Check-in exitoso! +15 puntos.');
        } else {
          setMessage('Ya has hecho check-in hoy.');
        }
      }
    } else {
      setMessage('Código QR inválido.');
    }
    setTimeout(() => setMessage(''), 4000);
  }, [user, setRewardQueue]);

  const metricsDataForChart = metrics.length > 0 ?
    metrics.reduce((acc: any, metric) => {
        const existing = acc.find((item: any) => item.exercise === metric.exercise);
        if (existing) {
            existing.data.push({ date: metric.date, load: metric.load });
        } else {
            acc.push({ exercise: metric.exercise, data: [{ date: metric.date, load: metric.load }] });
        }
        return acc;
    }, [])
    : [];

  const gamificationProfile = userProfile?.gamification;
