import React, { useState, useEffect } from 'react';
import { ChevronLeft, ChevronRight, X, Lock, AlertCircle, Calendar, Check, Handshake, Users, Repeat, ClipboardCheck } from 'lucide-react';
import { Session, View } from '../../types';
import { mockDb, addSession, replaceSession, mockUsers, mockTimestamp } from '../../services/mockData';

interface AgendaViewProps {
  userId?: string;
  userPlan?: string;
  setRewardQueue: (rewards: any) => void;
  setCurrentView?: (view: View) => void;
  isTrainer?: boolean;
}

// Helper to get the start of the week (Monday)
const getStartOfWeek = (date: Date) => {
    const d = new Date(date);
    d.setHours(0, 0, 0, 0);
    const day = d.getDay();
    const diff = d.getDate() - day + (day === 0 ? -6 : 1); // adjust when day is sunday
    return new Date(d.setDate(diff));
};

const AgendaView: React.FC<AgendaViewProps> = ({ userId, userPlan, setRewardQueue, setCurrentView, isTrainer }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDay, setSelectedDay] = useState<number | null>(null);
  const [modal, setModal] = useState<{ 
      type: string; 
      sessionTime: string; 
      sessionDay: number | null, 
      message?: string, 
      sessionToReplace?: Session, 
      clientName?: string,
      isRecurring?: boolean // Track if the user selected recurring
  }>({ type: 'none', sessionTime: '', sessionDay: null });

  const [bookedSessions, setBookedSessions] = useState<(Session & { clientName?: string })[]>([]);

  useEffect(() => {
    if (isTrainer) {
        // Collect ALL sessions from ALL users
        const allSessions: (Session & { clientName?: string })[] = [];
        Object.keys(mockDb).forEach(uid => {
            if (uid === 'trainer01') return;
            const userSessions = mockDb[uid].sessions || [];
            const userProfile = mockUsers.find(u => u.id === uid);
            const userName = userProfile ? (userProfile.displayName || userProfile.username) : 'Atleta';

            userSessions.forEach(s => {
                allSessions.push({ ...s, clientName: userName });
            });
        });
        setBookedSessions(allSessions);
    } else if (userId && mockDb[userId]) {
      // Safe access check for sessions for a single user
      const userSessions = mockDb[userId].sessions || [];
      setBookedSessions([...userSessions]);
    }
  }, [userId, isTrainer]);

  // Logic to determine if user can book an evaluation (No plan + 0 sessions)
  const isEligibleForEvaluation = !isTrainer && (!userPlan || userPlan === 'Sin Plan') && bookedSessions.length === 0;

  // Check if user has a valid plan (always true for trainer viewing agenda, or if eligible for eval)
  const hasPlan = isTrainer || (!!userPlan && userPlan !== 'Sin Plan');
  const canBook = hasPlan || isEligibleForEvaluation;

  const getGoogleCalendarUrl = (sessionDate: Date, sessionTime: string, isRecurring: boolean = false) => {
    const [hour, minute] = sessionTime.split(':');
    const startDateTime = new Date(sessionDate.getFullYear(), sessionDate.getMonth(), sessionDate.getDate(), parseInt(hour), parseInt(minute));
    const endDateTime = new Date(startDateTime);
    endDateTime.setHours(startDateTime.getHours() + 1);
    const formatDateTime = (date: Date) => date.toISOString().replace(/[-:]/g, '').split('.')[0] + 'Z';
    const title = encodeURIComponent("Sesión de Entrenamiento Tommybox");
    const description = encodeURIComponent(`Sesión de entrenamiento personal agendada.`);

    let url = `https://www.google.com/calendar/render?action=TEMPLATE&text=${title}&dates=${formatDateTime(startDateTime)}/${formatDateTime(endDateTime)}&details=${description}`;

    if (isRecurring) {
        // RRULE:FREQ=WEEKLY;UNTIL=YYYYMMDDTHHMMSSZ
        // Let's set it for 4 occurrences or end of month roughly
        url += `&recur=RRULE:FREQ=WEEKLY`;
    }

    return url;
  };

  const getIcsUrl = (sessionDate: Date, sessionTime: string, isRecurring: boolean = false) => {
    const [hour, minute] = sessionTime.split(':');
    const startDateTime = new Date(sessionDate.getFullYear(), sessionDate.getMonth(), sessionDate.getDate(), parseInt(hour), parseInt(minute));
    const endDateTime = new Date(startDateTime);
    endDateTime.setHours(startDateTime.getHours() + 1);
    const formatDateIcs = (date: Date) => date.toISOString().replace(/[-:]/g, '').replace(/\.\d{3}Z$/, '');

    let icsContent = `BEGIN:VCALENDAR\nVERSION:2.0\nPRODID:-//Tommybox//NONSGML v1.0//ES\nBEGIN:VEVENT\nUID:${new Date().getTime()}@tomybox.com\nDTSTAMP:${formatDateIcs(new Date())}\nDTSTART:${formatDateIcs(startDateTime)}\nDTEND:${formatDateIcs(endDateTime)}\nSUMMARY:Sesión de Entrenamiento Tommybox\nDESCRIPTION:Sesión de entrenamiento personal agendada.`;

    if (isRecurring) {
        icsContent += `\nRRULE:FREQ=WEEKLY`;
    }

    icsContent += `\nEND:VEVENT\nEND:VCALENDAR`;
    return `data:text/calendar;charset=utf8,${encodeURIComponent(icsContent)}`;
  };

  const daysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate();
  const firstDayOfMonth = (year: number, month: number) => new Date(year, month, 1).getDay();

  const totalDays = daysInMonth(currentDate.getFullYear(), currentDate.getMonth());
  const firstDay = firstDayOfMonth(currentDate.getFullYear(), currentDate.getMonth());
  const monthName = currentDate.toLocaleString('es-ES', { month: 'long', year: 'numeric' });

  const generateSessions = (date: Date) => {
    if (date.getDay() === 0) return []; // No sessions on Sunday
    const sessions = [];
    const now = new Date();

    // Find all bookings for this specific date
    const bookingsForDay = bookedSessions.filter(s => new Date(s.date + 'T00:00:00').toDateString() === date.toDateString());

    for (let hour = 9; hour <= 21; hour++) {
      const sessionTime = `${String(hour).padStart(2, '0')}:00`;

      const bookingsAtTime = bookingsForDay.filter(s => s.time === sessionTime);
      let status = 'disponible';
      let clientName = '';

      if (bookingsAtTime.length > 0) {
          status = 'agendado';
          // If trainer, grab the name. If multiple, join them (though simplistic logic assumes 1 slot/time usually)
          if (isTrainer) {
              clientName = bookingsAtTime.map(b => b.clientName).join(', ');
          }
      }

      if (new Date(date.getFullYear(), date.getMonth(), date.getDate(), hour) < now) status = 'pasado';

      sessions.push({ time: sessionTime, status, clientName });
    }
    return sessions;
  };

  const nextMonth = () => { setSelectedDay(null); setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1)); };
  const prevMonth = () => { setSelectedDay(null); setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1)); };

  const handleSlotClick = (sessionTime: string, status: string, clientName?: string) => {
      if (isTrainer) {
          if (status === 'agendado') {
             // Show details modal for trainer
             setModal({ type: 'trainer_view_details', sessionTime, sessionDay: selectedDay, clientName });
          }
          return; // Trainer doesn't book here
      }

      if (status !== 'disponible') return;
      handleBookSession(sessionTime);
  }

  const handleBookSession = (sessionTime: string) => {
    if (!userId) { alert("Debes iniciar sesión para agendar."); return; }

    if (!canBook) { 
        alert("Necesitas un plan para agendar sesiones.");
        return; 
    }
    if (!selectedDay) { alert("Por favor, selecciona un día del calendario."); return; }

    // Evaluation Logic Hook
    if (isEligibleForEvaluation) {
        setModal({ type: 'evaluation_confirm', sessionTime, sessionDay: selectedDay });
        return;
    }

    const planLimits: { [key: string]: number } = {
      '1 Sesión / Semana': 1,
      '2 Sesiones / Semana': 2,
      '3 Sesiones / Semana': 3,
    };
    const sessionLimit = planLimits[userPlan!] || 0;
    if (sessionLimit === 0) {
        alert("Tu plan actual no permite agendar sesiones, por favor actualízalo.");
        return;
    }

    const selectedDate = new Date(currentDate.getFullYear(), currentDate.getMonth(), selectedDay);
    const startOfWeek = getStartOfWeek(selectedDate);
    const endOfWeek = new Date(startOfWeek);
    endOfWeek.setDate(startOfWeek.getDate() + 6);
    endOfWeek.setHours(23, 59, 59, 999);

    const sessionsThisWeek = bookedSessions.filter(s => {
      const sessionDate = new Date(s.date + 'T00:00:00');
      return sessionDate >= startOfWeek && sessionDate <= endOfWeek;
    });

    if (sessionsThisWeek.length >= sessionLimit) {
      const earliestSession = sessionsThisWeek.sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())[0];
      setModal({ 
        type: 'replace_confirmation', 
        sessionTime, 
        sessionDay: selectedDay, 
        sessionToReplace: earliestSession 
      });
    } else {
      setModal({ type: 'book_options', sessionTime, sessionDay: selectedDay });
    }
  };

  const handleConfirmBooking = (recurring: boolean = false) => {
    if (!userId || !modal.sessionDay) return;

    // Base selected date
    const selectedDayDate = new Date(currentDate.getFullYear(), currentDate.getMonth(), modal.sessionDay);

    const sessionsToBook: Session[] = [];

    // Create first session
    sessionsToBook.push({
        id: `session_${Date.now()}_0`,
        date: selectedDayDate.toISOString().split('T')[0],
        time: modal.sessionTime,
        timestamp: mockTimestamp(new Date()), // Use actual mockTimestamp
    });

    if (recurring) {
        // Find subsequent dates for the rest of the month
        const dayOfWeek = selectedDayDate.getDay(); // 1 (Mon) to 6 (Sat)
        let nextDate = new Date(selectedDayDate);
        nextDate.setDate(nextDate.getDate() + 7); // Start with next week

        while (nextDate.getMonth() === selectedDayDate.getMonth()) {
            sessionsToBook.push({
                id: `session_${Date.now()}_${sessionsToBook.length}`,
                date: nextDate.toISOString().split('T')[0],
                time: modal.sessionTime,
                timestamp: mockTimestamp(new Date()),
            });
            nextDate.setDate(nextDate.getDate() + 7);
        }
    }

    // Process all sessions
    let rewards = null;
    const newBookedSessions = [...bookedSessions];

    sessionsToBook.forEach((s, idx) => {
        // Only award points for the first one to avoid spamming alerts, or adjust logic
        const r = addSession(userId, s);
        if (idx === 0) rewards = r;
        newBookedSessions.push({ ...s });
    });

    if(rewards) setRewardQueue((q: any) => [...q, rewards]);

    setBookedSessions(newBookedSessions);
    setModal({ type: 'booked_success', sessionTime: modal.sessionTime, sessionDay: modal.sessionDay, isRecurring: recurring });
  };

  const handleConfirmReplacement = () => {
    if (!userId || !modal.sessionDay || !modal.sessionToReplace) return;
    const selectedDayDate = new Date(currentDate.getFullYear(), currentDate.getMonth(), modal.sessionDay);
    const newSession: Session = {
        id: `session_${Date.now()}`,
        date: selectedDayDate.toISOString().split('T')[0],
        time: modal.sessionTime,
        timestamp: mockTimestamp(new Date()),
    };

    replaceSession(userId, modal.sessionToReplace.id, newSession);
    const rewards = addSession(userId, newSession);
    if (rewards) setRewardQueue((q: any) => [...q, rewards]);

    const updatedSessions = bookedSessions.filter(s => s.id !== modal.sessionToReplace!.id);
    updatedSessions.push(newSession);

    setBookedSessions(updatedSessions);
    setModal({ type: 'booked_success', sessionTime: modal.sessionTime, sessionDay: modal.sessionDay, isRecurring: false });
  };

  const today = new Date();
  const selectedDayDate = selectedDay ? new Date(currentDate.getFullYear(), currentDate.getMonth(), selectedDay) : null;
  const sessionsForSelectedDay = selectedDayDate ? generateSessions(selectedDayDate) : [];

  const currentMonthBookedDays = bookedSessions
    .filter(s => {
      const sessionDate = new Date(s.date + 'T00:00:00');
      return sessionDate.getFullYear() === currentDate.getFullYear() && sessionDate.getMonth() === currentDate.getMonth();
    })
    .map(s => new Date(s.date + 'T00:00:00').getDate());

  return (
    <section className="bg-gray-100 min-h-screen py-8 px-4">
      <div className="max-w-4xl mx-auto">
        {/* PLAN WARNING OR EVALUATION PROMPT */}
        {!canBook ? (
             <div className="bg-red-50 border-l-4 border-red-500 p-6 mb-6 rounded-lg shadow-sm flex flex-col sm:flex-row items-center justify-between gap-4">
                 <div className="flex items-start gap-4">
                    <div className="p-2 bg-red-100 rounded-full text-red-600">
                        <Lock size={24} />
                    </div>
                    <div>
                        <h3 className="font-bold text-red-800 text-lg">Agenda Bloqueada</h3>
                        <p className="text-sm text-red-600 mt-1">Necesitas un plan activo para poder agendar tus sesiones de entrenamiento.</p>
                    </div>
                 </div>
                 <button 
                    onClick={() => setCurrentView && setCurrentView('plans')} 
                    className="w-full sm:w-auto bg-red-600 text-white px-6 py-2 rounded-full text-sm font-bold hover:bg-red-700 transition-colors shadow-md"
                >
                    Ver Planes Disponibles
                 </button>
             </div>
        ) : isEligibleForEvaluation ? (
             <div className="bg-blue-600 p-6 mb-6 rounded-2xl shadow-lg text-white flex flex-col sm:flex-row items-center justify-between gap-4 animate-fade-in relative overflow-hidden">
                 <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -mr-10 -mt-10 blur-xl"></div>
                 <div className="flex items-start gap-4 relative z-10">
                    <div className="p-3 bg-white/20 rounded-full">
                        <ClipboardCheck size={28} />
                    </div>
                    <div>
                        <h3 className="font-bold text-white text-xl">Agenda tu Evaluación</h3>
                        <p className="text-blue-100 mt-1">Selecciona un día y hora disponible para tu sesión de diagnóstico gratuita.</p>
                    </div>
                 </div>
             </div>
        ) : null}

        {/* Trainer Header */}
        {isTrainer && (
             <div className="bg-blue-600 p-6 mb-6 rounded-2xl shadow-md text-white flex items-center gap-4">
                 <div className="p-3 bg-white/20 rounded-full">
                     <Users size={28} />
                 </div>
                 <div>
                     <h2 className="text-xl font-bold">Vista de Entrenador</h2>
                     <p className="opacity-90 text-sm">Estás viendo la agenda global de todos los atletas.</p>
                 </div>
             </div>
        )}

        <div className={`bg-white rounded-2xl shadow-lg overflow-hidden p-6 transition-opacity duration-300 ${!canBook ? 'opacity-75 grayscale-[0.5] pointer-events-none select-none' : ''}`}>
          <div className="flex justify-between items-center mb-6">
            <h3 className="text-2xl font-bold text-gray-800 capitalize">{monthName}</h3>
            <div className="flex items-center space-x-2">
              <button onClick={prevMonth} className="p-2 rounded-full hover:bg-gray-100 transition-colors duration-200" disabled={currentDate.getMonth() <= today.getMonth() && currentDate.getFullYear() <= today.getFullYear()}><ChevronLeft size={24} /></button>
              <button onClick={nextMonth} className="p-2 rounded-full hover:bg-gray-100 transition-colors duration-200"><ChevronRight size={24} /></button>
            </div>
          </div>

          {/* Days Grid */}
          <div className="grid grid-cols-7 text-center font-bold text-gray-400 text-sm mb-2 uppercase tracking-wide">
            {['Lun', 'Mar', 'Mié', 'Jue', 'Vie', 'Sáb', 'Dom'].map(day => <div key={day} className="py-2">{day}</div>)}
          </div>
          <div className="grid grid-cols-7 gap-2">
            {Array.from({ length: firstDay === 0 ? 6 : firstDay - 1 }).map((_, index) => <div key={`empty-${index}`} className="aspect-square"></div>)}
            {Array.from({ length: totalDays }).map((_, index) => {
              const day = index + 1;
              const date = new Date(currentDate.getFullYear(), currentDate.getMonth(), day);
              const isToday = day === today.getDate() && currentDate.getMonth() === today.getMonth() && currentDate.getFullYear() === today.getFullYear();
              const isPastDay = date < new Date(today.getFullYear(), today.getMonth(), today.getDate());
              const hasBookedSession = currentMonthBookedDays.includes(day);
              const isSunday = date.getDay() === 0;

              let dayClass = `relative flex flex-col items-center justify-center rounded-xl transition-all duration-200 aspect-square border-2 `;

              if (isPastDay || isSunday) {
                  dayClass += 'bg-gray-50 text-gray-300 border-transparent cursor-not-allowed ';
              } else if (selectedDay === day) {
                  dayClass += 'bg-blue-600 text-white border-blue-600 shadow-md transform scale-105 z-10 cursor-pointer ';
              } else {
                  dayClass += 'bg-white text-gray-700 border-gray-100 hover:border-blue-300 cursor-pointer hover:shadow-sm ';
              }

              if (isToday && selectedDay !== day) dayClass += 'border-green-400 text-green-600 ';

              return (
                <div key={day} onClick={() => (!isPastDay && !isSunday) && setSelectedDay(selectedDay === day ? null : day)} className={dayClass}>
                  <span className="text-lg font-bold">{day}</span>
                  {hasBookedSession && (
                      <span className={`absolute bottom-2 w-1.5 h-1.5 rounded-full ${selectedDay === day ? 'bg-white' : 'bg-blue-500'}`}></span>
                  )}
                </div>
              );
            })}
          </div>

          {/* Slots Section */}
          <div className="mt-8 pt-6 border-t border-gray-100">
            {selectedDayDate ? (
              <div className="animate-fade-in">
                <h4 className="text-lg font-bold text-gray-800 mb-4 flex items-center">
                    Horarios {isTrainer && <span className="ml-2 text-blue-600">(Global)</span>} <span className="ml-2 px-2 py-1 bg-gray-100 rounded text-xs text-gray-500 font-normal">{selectedDayDate.toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric' })}</span>
                </h4>

                {sessionsForSelectedDay.length > 0 ? (
                  <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                    {sessionsForSelectedDay.map((session, index) => (
                      <button 
                        key={index} 
                        disabled={session.status === 'pasado'}
                        onClick={() => handleSlotClick(session.time, session.status, session.clientName)}
                        className={`
                            relative flex flex-col items-center justify-center p-3 rounded-lg border transition-all
                            ${session.status === 'agendado' ? (isTrainer ? 'bg-indigo-50 border-indigo-200 text-indigo-800 cursor-pointer hover:bg-indigo-100' : 'bg-blue-50 border-blue-200 text-blue-700 opacity-80 cursor-default') : 
                              session.status === 'disponible' ? 'bg-white border-gray-200 hover:border-blue-500 hover:bg-blue-50 hover:text-blue-700 cursor-pointer shadow-sm' : 
                              'bg-gray-50 border-transparent text-gray-300 cursor-not-allowed'}
                        `}
                      >
                        <span className="font-bold text-lg">{session.time}</span>
                        {isTrainer && session.status === 'agendado' ? (
                            <span className="text-[11px] uppercase tracking-wide mt-1 font-bold text-center leading-tight truncate w-full px-1">
                                {session.clientName || 'Ocupado'}
                            </span>
                        ) : (
                            <span className="text-[10px] uppercase tracking-wide mt-1 font-semibold">
                                {session.status}
                            </span>
                        )}
                      </button>
                    ))}
                  </div>
                ) : <p className="text-sm italic text-gray-500">No hay sesiones programadas para este día.</p>}
              </div>
            ) : (
                <div className="text-center py-12 text-gray-400">
                    <Calendar size={48} className="mx-auto mb-3 opacity-20"/>
                    <p>Selecciona un día para ver los horarios.</p>
                </div>
            )}
          </div>
        </div>
      </div>

      {/* Modals */}
      {modal.type === 'replace_confirmation' && modal.sessionToReplace && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in">
          <div className="bg-white rounded-2xl p-6 max-w-sm w-full mx-auto shadow-2xl text-center transform transition-all scale-100">
            <AlertCircle className="mx-auto text-orange-500 mb-4" size={48} />
            <h3 className="text-xl font-bold text-gray-900">Límite Semanal Alcanzado</h3>
            <p className="mt-2 text-sm text-gray-600">Tu plan solo permite ciertas sesiones por semana. ¿Quieres cambiar tu sesión del <strong>{new Date(modal.sessionToReplace.date).toLocaleDateString('es-ES', { timeZone: 'UTC' })}</strong> por esta nueva fecha?</p>
            <div className="mt-6 flex flex-col gap-3">
              <button onClick={handleConfirmReplacement} className="w-full rounded-xl bg-orange-500 px-6 py-3 text-white font-bold hover:bg-orange-600 transition-colors shadow-lg shadow-orange-200">Sí, cambiar sesión</button>
              <button onClick={() => setModal({ type: 'none', sessionTime: '', sessionDay: null })} className="w-full rounded-xl bg-gray-100 px-6 py-3 text-gray-700 font-bold hover:bg-gray-200 transition-colors">Cancelar</button>
            </div>
          </div>
        </div>
      )}

      {/* EVALUATION CONFIRM MODAL */}
      {modal.type === 'evaluation_confirm' && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in">
          <div className="bg-white rounded-2xl p-8 max-w-sm w-full mx-auto shadow-2xl text-center">
            <div className="w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center mx-auto mb-4">
                 <ClipboardCheck className="text-blue-600" size={32} />
            </div>
            <h3 className="text-2xl font-bold text-gray-900">Confirmar Evaluación</h3>
            <p className="mt-2 text-gray-600 mb-2">
                Estás agendando tu sesión de diagnóstico gratuita para el:
            </p>
            <p className="text-lg font-bold text-blue-600 mb-6">
                 {modal.sessionDay} de {monthName} a las {modal.sessionTime}
            </p>
            <p className="text-xs text-gray-500 bg-gray-50 p-3 rounded-lg border border-gray-100 mb-6">
                Esta sesión es clave para que tu entrenador defina tu plan de entrenamiento personalizado.
            </p>

            <button 
                onClick={() => handleConfirmBooking(false)} 
                className="w-full rounded-xl bg-blue-600 px-4 py-3 text-white font-bold hover:bg-blue-700 shadow-lg shadow-blue-200"
            >
                Confirmar Sesión
            </button>
            <button 
                onClick={() => setModal({ type: 'none', sessionTime: '', sessionDay: null })} 
                className="mt-3 w-full rounded-xl bg-white border border-gray-200 px-4 py-3 text-gray-700 font-bold hover:bg-gray-50"
            >
                Cancelar
            </button>
          </div>
        </div>
      )}

      {/* Booking Options Modal (Single vs Recurring) */}
      {modal.type === 'book_options' && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in">
          <div className="bg-white rounded-2xl p-8 max-w-md w-full mx-auto shadow-2xl text-center">
            <h3 className="text-2xl font-bold text-gray-900">Confirmar Reserva</h3>
            <p className="mt-4 text-lg text-gray-600">
                {modal.sessionDay} de {monthName} <br/>
                <span className="text-3xl font-bold text-blue-600 mt-2 block">{modal.sessionTime}</span>
            </p>

            <div className="mt-8 grid gap-4">
                <button 
                    onClick={() => handleConfirmBooking(false)} 
                    className="w-full rounded-xl bg-blue-600 px-4 py-3 text-white font-bold hover:bg-blue-700 shadow-lg shadow-blue-200 flex items-center justify-center gap-2"
                >
                    <Check size={20} />
                    Reservar solo este día
                </button>

                <button 
                    onClick={() => handleConfirmBooking(true)} 
                    className="w-full rounded-xl bg-white border-2 border-blue-600 px-4 py-3 text-blue-600 font-bold hover:bg-blue-50 transition-colors flex items-center justify-center gap-2"
                >
                    <Repeat size={20} />
                    Reservar todo el mes
                    <span className="text-xs bg-blue-100 px-2 py-0.5 rounded-full ml-1 font-medium">Mismo horario</span>
                </button>
            </div>

            <button 
                onClick={() => setModal({ type: 'none', sessionTime: '', sessionDay: null })} 
                className="mt-4 w-full rounded-xl bg-gray-100 px-4 py-3 text-gray-700 font-bold hover:bg-gray-200"
            >
                Cancelar
            </button>
          </div>
        </div>
      )}

      {/* Trainer View Details Modal */}
      {modal.type === 'trainer_view_details' && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in">
          <div className="bg-white rounded-2xl p-6 max-w-sm w-full mx-auto shadow-2xl text-center relative">
            <button onClick={() => setModal({ type: 'none', sessionTime: '', sessionDay: null })} className="absolute top-4 right-4 text-gray-400 hover:text-gray-600"><X size={20}/></button>
            <div className="w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center mx-auto mb-4 mt-2">
                <Users className="text-blue-600" size={32} />
            </div>
            <h3 className="text-xl font-bold text-gray-900">Detalles de la Sesión</h3>
            <p className="text-sm text-gray-500 mb-4">{modal.sessionDay} de {monthName} a las {modal.sessionTime}</p>

            <div className="bg-gray-50 p-4 rounded-xl border border-gray-100">
                <p className="text-xs text-gray-400 font-bold uppercase mb-1">Atleta Agendado</p>
                <p className="text-lg font-bold text-gray-800">{modal.clientName || 'Desconocido'}</p>
            </div>

            <button onClick={() => setModal({ type: 'none', sessionTime: '', sessionDay: null })} className="w-full mt-6 rounded-xl bg-blue-600 px-6 py-3 text-white font-bold hover:bg-blue-700 transition-colors shadow-lg">
                Cerrar
            </button>
          </div>
        </div>
      )}

      {/* Success Modal with Calendar Sync */}
      {modal.type === 'booked_success' && selectedDayDate && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in">
          <div className="bg-white rounded-2xl p-6 max-w-sm w-full mx-auto shadow-2xl text-center relative overflow-hidden animate-scale-up">
            <div className="absolute top-0 left-0 w-full h-2 bg-green-500"></div>
            <button onClick={() => setModal({ type: 'none', sessionTime: '', sessionDay: null })} className="absolute top-4 right-4 text-gray-400 hover:text-gray-600"><X size={20}/></button>
            <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4 mt-4">
                <Check className="text-green-600" size={32} />
            </div>
            <h3 className="text-2xl font-bold text-gray-900">¡Listo!</h3>
            <p className="mt-2 text-gray-600">
                {modal.isRecurring 
                    ? 'Tus sesiones mensuales han sido agendadas.' 
                    : 'Tu sesión ha sido agendada.'}
            </p>

            {/* Calendar Sync Options */}
            <div className="mt-6 flex flex-col space-y-3">
              <p className="text-xs text-gray-400 font-medium uppercase tracking-wider mb-1">Sincronizar Calendario</p>
              <a href={getGoogleCalendarUrl(selectedDayDate, modal.sessionTime, modal.isRecurring)} target="_blank" rel="noopener noreferrer" className="w-full rounded-xl bg-blue-600 px-6 py-3 text-white font-bold hover:bg-blue-700 flex items-center justify-center gap-2">
                  <Calendar size={18}/> Google Calendar
              </a>
              <a href={getIcsUrl(selectedDayDate, modal.sessionTime, modal.isRecurring)} download="training-session.ics" className="w-full rounded-xl bg-gray-100 px-6 py-3 text-gray-700 font-bold hover:bg-gray-200">Descargar para iOS / Outlook</a>
            </div>
          </div>
        </div>
      )}
    </section>
  );
};

export default AgendaView;
